   205→  constructor() {
   206→    this.failures = {};          // { 'provider:modality': { count, lastFailure, error, status } }
   207→    this.activeProviders = {};   // { modality: providerKey }
   208→    this.logs = [];              // Recent failover events (last 100)
   209→    this.stats = {               // Cumulative stats
