   224→
   225→  _initClients() {
   226→    // Anthropic client (Polsia proxy) — primary for LLM text
   227→    if (process.env.POLSIA_API_URL && process.env.POLSIA_API_KEY) {
   228→      this.clients.anthropic = new Anthropic({
   229→        baseURL: process.env.POLSIA_API_URL,
   230→        apiKey: process.env.POLSIA_API_KEY,
   231→      });
   232→    }
   233→
   234→    // OpenAI client (Polsia proxy) — primary for vision, TTS, ASR
   235→    if (process.env.OPENAI_BASE_URL && process.env.OPENAI_API_KEY) {
   236→      this.clients.openai = new OpenAI({
   237→        baseURL: process.env.OPENAI_BASE_URL,
   238→        apiKey: process.env.OPENAI_API_KEY,
   239→      });
   240→      this.openaiBaseUrl = process.env.OPENAI_BASE_URL;
