   242→    }
   243→
   244→    // NVIDIA NIM client — fallback for all modalities
   245→    const nimKey = process.env.NVIDIA_NIM_API_KEY;
   246→    const nimBase = process.env.NIM_BASE_URL || 'https://integrate.api.nvidia.com/v1';
   247→    if (nimKey) {
   248→      this.clients.nim = new OpenAI({
   249→        baseURL: nimBase,
   250→        apiKey: nimKey,
   251→      });
   252→      this.nimBaseUrl = nimBase;
   253→      this.nimApiKey = nimKey;
   254→      this.nimAvailable = true;
   255→    }
   256→
   257→    // Deepgram client — independent fallback for TTS + ASR (pure REST, no SDK)
   258→    // Provides real failover when OpenAI audio endpoints are down/rate-limited.
   259→    // Sign up at https://deepgram.com (free $200 credit) and set DEEPGRAM_API_KEY.
   260→    const dgKey = process.env.DEEPGRAM_API_KEY;
   261→    if (dgKey) {
   262→      this.deepgramApiKey = dgKey;
   263→      this.deepgramAvailable = true;
   264→      console.log('[ai-provider] Deepgram available for TTS/ASR fallback');
   265→    } else {
   266→      this.deepgramAvailable = false;
   267→    }
   268→
   269→    // Self-hosted audio — whisper.cpp (STT) + Piper (TTS), no API keys
   270→    // Layer 2 fallback: OpenAI → Self-hosted → Deepgram
   271→    this.selfHostedSTTAvailable = false;
   272→    this.selfHostedTTSAvailable = false;
   273→    if (selfHostedAudio) {
   274→      try {
   275→        const { sttAvailable, ttsAvailable } = selfHostedAudio.initialize();
   276→        this.selfHostedSTTAvailable = sttAvailable;
   277→        this.selfHostedTTSAvailable = ttsAvailable;
   278→      } catch (e) {
   279→        console.log('[ai-provider] Self-hosted audio init failed:', e.message);
   280→      }
   281→    }
   282→  }
