   286→  /**
   287→   * Get the fallback chain for a modality, optionally specialized per module.
   288→   * @param {string} modality - 'llm', 'vision', 'tts', 'asr', 'embedding', 'reranking', 'safety'
   289→   * @param {string} variant - Chain variant: 'default', 'quality', 'efficient', 'reasoning', 'document'
   290→   * @returns {string[]} Array of provider keys to try in order
   291→   */
   292→  getChain(modality, variant = 'default') {
   293→    const chains = {
   294→      // ─── LLM Chains (7-10 providers deep) ────────────────
   295→      llm: {
   296→        // Default: balanced quality and cost
   297→        default: [
   298→          'anthropic',           // Polsia/Claude — current primary
   299→          'openai',              // Polsia/OpenAI GPT-4o-mini
   300→          'nim_nemotron_super',  // NIM Nemotron Super 49B — best value
   301→          'nim_kimi',            // NIM Kimi K2.5 — 1T MoE multimodal
   302→          'nim_deepseek_v3',     // NIM DeepSeek V3.2 — GPT-5 level
