   304→          'nim_step_flash',      // NIM Step 3.5 Flash — ultra efficient
   305→          'nim_qwen_72b',        // NIM Qwen 2.5 72B — 95%+ GPT-4 parity
   306→          'nim_gpt_oss',         // NIM GPT-OSS-120B — OpenAI open model
   307→        ],
   308→        // Quality: best models first for critical tasks (interviews, coaching)
   309→        quality: [
   310→          'anthropic',
   311→          'openai',
   312→          'nim_deepseek_v3',     // DeepSeek V3.2 — strongest open model
   313→          'nim_kimi',            // Kimi K2.5 — multimodal reasoning
   314→          'nim_deepseek_v3_1',   // DeepSeek V3.1 — hybrid thinking
   315→          'nim_nemotron_super',  // Nemotron Super 49B
   316→          'nim_qwen_72b',        // Qwen 2.5 72B — strong math
   317→          'nim_step_flash',
   318→          'nim_gpt_oss',
   319→        ],
   320→        // Efficient: cheapest models first for bulk/simple tasks
   321→        efficient: [
