   326→          'nim_nemotron_super',  // Nemotron Super 49B — $0.10/$0.40
   327→          'nim_qwen_72b',        // Qwen 2.5 72B — ~$0.30/$0.30
   328→          'nim_gpt_oss',
   329→        ],
