          'nim_deepseek_v3',     // DeepSeek V3.2 — strong reasoning
          'nim_kimi',            // Kimi K2.5 — thinking mode
          'nim_nemotron_super',
        ],
      },

      // ─── Vision Chains (4-5 providers deep) ──────────────
      vision: {
        default: [
          'openai_vision',       // Polsia/OpenAI GPT-4o
          'nim_cosmos',          // NIM Cosmos Reason2 8B
          'nim_nemotron_vl',     // NIM Nemotron Nano 12B VL
          'nim_kimi_vision',     // NIM Kimi K2.5 (multimodal)
          'nim_gemma_vision',    // NIM Gemma 3 27B (140+ languages, multimodal)
        ],
        // Document/OCR chain for resume parsing
        document: [
          'openai_vision',       // Polsia/OpenAI GPT-4o
          'nim_nemotron_vl',     // NIM Nemotron Nano 12B VL — good at documents
          'nim_kimi_vision',     // NIM Kimi K2.5 — PDF native
          'nim_gemma_vision',    // NIM Gemma 3 27B — multilingual
          'nim_cosmos',          // NIM Cosmos Reason2 8B
        ],
      },

      // ─── TTS Chains (3-layer: OpenAI → Self-hosted → Deepgram) ─
      // Layer 1: OpenAI TTS-1 (primary, best quality)
      // Layer 2: Piper TTS (self-hosted CPU, no API key, free)
      // Layer 3: Deepgram Aura (paid fallback, user's API key)
      // Layer 4: Browser Web Speech API (frontend-only, last resort)
      tts: {
        default: [
          'openai_tts',          // Layer 1: Polsia/OpenAI TTS-1
          'selfhosted_tts',      // Layer 2: Piper TTS (CPU, no API key)
          'deepgram_tts',        // Layer 3: Deepgram Aura (paid, $200 free credit)
        ],
      },

      // ─── ASR Chains (3-layer: OpenAI → Self-hosted → Deepgram) ─
      // Layer 1: OpenAI Whisper (primary, best accuracy)
      // Layer 2: whisper.cpp tiny.en (self-hosted CPU, no API key, free)
      // Layer 3: Deepgram Nova-2 (paid fallback, user's API key)
      asr: {
        default: [
          'openai_whisper',      // Layer 1: Polsia/OpenAI Whisper
          'selfhosted_stt',      // Layer 2: whisper.cpp tiny.en (CPU, no API key)
          'deepgram_stt',        // Layer 3: Deepgram Nova-2 (paid, $200 free credit)
        ],
      },

      // ─── Embedding Chains (3 providers deep) ─────────────
      embedding: {
        default: [
          'openai_embed',        // Polsia/OpenAI text-embedding-3-small
          'nim_embed_qa',        // NIM NV-EmbedQA 1B v2 — 26 languages
          'nim_embed_vl',        // NIM Nemotron-Embed-VL 1B — multimodal
